> **Note:**&#x20;
>
> Example Setup
>
> This example connects to an instance of MongoDB by using a
> connection URI. To learn more about connecting to your MongoDB
> instance, see the [Connect to MongoDB](node-connect) guide. This example
> also uses the `movies` collection in the `sample_mflix` database
> included in the [Atlas sample datasets](atlas/sample-data). You
> can load them into your database on the free tier of MongoDB Atlas by
> following the [MongoDB Get Started](get-started).The following snippet retrieves a list of distinct values for the `year`
document field from the `movies` collection. It uses a query document to
match movies that include `"Barbara Streisand"` in the `director` array.**JavaScript:**JavaScript```javascript
import { MongoClient } from "mongodb";

// Replace the uri string with your MongoDB deployment's connection string.
const uri = "<connection string uri>";

const client = new MongoClient(uri);

async function run() {
  try {

    // Get the database and collection on which to run the operation
    const database = client.db("sample_mflix");
    const movies = database.collection("movies");

    // Specify the document field to find distinct values for
    const fieldName = "year";

    // Specify an optional query document to narrow results
    const query = { directors: "Barbra Streisand" };

    // Execute the distinct operation
    const distinctValues = await movies.distinct(fieldName, query);

    // Print the result
    console.log(distinctValues);
  } finally {
    await client.close();
  }
}
run().catch(console.dir);

```**TypeScript:**TypeScript```typescript
import { MongoClient } from "mongodb";

// Replace the uri string with your MongoDB deployment's connection string.
const uri = "<connection string uri>";

const client = new MongoClient(uri);

interface Movie {
  directors: string;
  year: number;
}

async function run() {
  try {
    // define a database and collection on which to run the method
    const database = client.db("sample_mflix");
    const movies = database.collection<Movie>("movies");

    const distinctValues = await movies.distinct("year", {
      directors: "Barbra Streisand",
    });

    console.log(distinctValues);
  } finally {
    await client.close();
  }
}
run().catch(console.dir);

```Running the preceding example, results in the following output:```json
[ 1983, 1991, 1996 ]
```

